import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Create Branch Links for Product Feeds","description":"","frontmatter":{"title":"Create Branch Links for Product Feeds","slug":"creating-branch-links-for-product-feeds"},"headers":[],"relativePath":"marketer-hub/creating-branch-links-for-product-feeds.md","filePath":"marketer-hub/creating-branch-links-for-product-feeds.md"}'),i={name:"marketer-hub/creating-branch-links-for-product-feeds.md"};function n(d,e,l,s,p,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A product feed or catalog is essentially an inventory of all your products and contain information like images, prices, descriptions and more. These attributes are used to define each one of your products in a unique way. Your product feed or catalog should reflect your business type, consisting of different attributes that are specific to your products.<br> Your Branch link ensures your users are taken to the correct product feed or catalog content and when used as part of your dynamic and responsive marketing efforts, they allow you to effectively engage with users who have expressed interest in a wide range of your products across both web and app.</p><h2 id="prerequisites-for-product-feeds" tabindex="-1">Prerequisites for Product Feeds <a class="header-anchor" href="#prerequisites-for-product-feeds" aria-label="Permalink to &quot;Prerequisites for Product Feeds&quot;">​</a></h2><ul><li>Branch SDK</li><li>Branch Web SDK</li><li>Deep Link Routing set up in your Branch dashboard</li><li>Facebook and/or Google Ads integrations enabled in your Branch Dashboard</li><li>Link per product feed item</li></ul><p><strong>If you want to support routing to your app (not just web) for Google Ads</strong></p><ul><li>Universal Links and/or App Links enabled on your primary home domain</li></ul><h2 id="google-feeds" tabindex="-1">Google Feeds <a class="header-anchor" href="#google-feeds" aria-label="Permalink to &quot;Google Feeds&quot;">​</a></h2><h3 id="creating-branch-tracking-links" tabindex="-1">Creating Branch Tracking Links <a class="header-anchor" href="#creating-branch-tracking-links" aria-label="Permalink to &quot;Creating Branch Tracking Links&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">IMPORTANT - MUST COMPLETE</p><p>You must include Branch Links in the <strong>Tracking Template</strong> field of your campaign settings <strong>AFTER</strong> you created your campaign</p></div><div class="info custom-block"><p class="custom-block-title">No Cross-Domain Redirects</p><p>Since your product feed items&#39; landing pages must match your display URL and not contain any cross-domain redirects, you cannot put a Branch link directly in the Final URL field</p></div><ol><li><p>Start with your base domain.</p><ol><li>e.g. <code>https://example.app.link</code></li></ol></li><li><p>Add your deep link data as query parameters. NOTE: Be sure to URI encode each query parameter.<br> 2. e.g. <code>https://example.app.link?product_id=123&amp;category=shoes</code></p></li><li><p>Add <a href="./creating-a-deep-link.html#fallback-to-a-specific-url">fallback URLs</a> to point to your website (i.e., Google&#39;s <code>{lpurl}</code> macro will auto-populate the final url of the ad)<br> 3. e.g. <code>https://example.app.link?product_id=123&amp;category=shoes&amp;$fallback_url={lpurl}</code></p></li><li><p>Finally, add the following analytics parameters needed to categorize your data accurately.</p><ol><li><a href="./creating-a-deep-link.html">Generic Branch Analytics Parameters</a></li><li>Google Ads Analytics Parameters:</li></ol></li></ol><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Parameter</strong></td><td><strong>Value</strong></td></tr><tr><td>$3p</td><td>a_google_adwords</td></tr><tr><td>~advertising_partner_name</td><td>Google AdWords</td></tr><tr><td>$one_time_use</td><td>false</td></tr><tr><td>~branch_ad_format</td><td>Cross-Platform Display OR App Only</td></tr><tr><td>~channel</td><td>Display OR Shopping</td></tr><tr><td>~feature</td><td>paid advertising</td></tr><tr><td>~campaign</td><td>{{campaign.name}}</td></tr><tr><td>~ad_id</td><td>{{ad.id}}</td></tr><tr><td>~ad_set_id</td><td>{{adset.id}}</td></tr><tr><td>~campaign_id</td><td>{{campaign.id}}</td></tr></tbody></table><p>Your Branch long link for Google Ads should look like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.app.link?product_id=123&amp;category=shoes&amp;$fallback_url=https://branch.io/universal-ads/&amp;$3p=a_google_adwords&amp;~advertising_partner_name=Google-Adwords&amp;$one_time_use=false&amp;branch_ad_format=Cross-Platform Search&amp;~channel=Google Adwords&amp;~feature=paid advertising&amp;~ad_set_id={adgroupid}&amp;~campaign_id={campaignid}&amp;~keyword={keyword}&amp;~placement={placement}&amp;~gclid={gclid}&amp;~lpurl={lpurl}&amp;$android_deepview=false&amp;$ios_deepview=false&amp;$desktop_deepview=false&amp;$android_passive_deepview=false&amp;$ios_passive_deepview=false</span></span></code></pre></div><h3 id="creating-a-google-feed" tabindex="-1">Creating a Google Feed <a class="header-anchor" href="#creating-a-google-feed" aria-label="Permalink to &quot;Creating a Google Feed&quot;">​</a></h3><p>The type of feed you create should match the business type you selected when creating your Dynamic remarketing campaign. Use the &quot;Custom&quot; feed only if the other business types don&#39;t apply to your products or services.<br> Please refer to Google’s <a href="https://support.google.com/google-ads/answer/6053288?hl=en&amp;ref_topic=3180758" target="_blank" rel="noreferrer">Create a feed for your responsive ads</a> for the following:</p><ul><li>About feeds</li><li>Get feed templates and specs for your business type</li><li>Create and upload a new feed</li><li>Fix problems with your feed</li></ul><h4 id="placing-your-link-in-the-product-feed" tabindex="-1">Placing your Link in the Product Feed <a class="header-anchor" href="#placing-your-link-in-the-product-feed" aria-label="Permalink to &quot;Placing your Link in the Product Feed&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">Opening the Mobile App</p><p>If you are using Universal links and/or Android App links on your primary domain, including those links in the <code>link</code> column will result in the app opening for users with the app installed. By default, all links will open your webpage in your mobile browser, unless Universal Links and/or Android App links are enabled on your primary domain.</p></div><p>When creating your product feed, one of the required parameters is the <code>link</code> parameter. The <code>link</code> parameter is typically a URL link to merchant&#39;s site (website landing page) where you can purchase or learn more about the item.</p><h3 id="uploading-your-feed-to-google-ads" tabindex="-1">Uploading Your Feed to Google Ads <a class="header-anchor" href="#uploading-your-feed-to-google-ads" aria-label="Permalink to &quot;Uploading Your Feed to Google Ads&quot;">​</a></h3><p>There are limits to the number of feeds and feed items per account. Learn more <a href="https://support.google.com/google-ads/answer/6372658" target="_blank" rel="noreferrer">About Google Ads account limits.</a></p><p>To upload your product feed to Google Ads, please follow Google’s help document on <a href="https://support.google.com/google-ads/answer/6053288?hl=en&amp;ref_topic=3180758" target="_blank" rel="noreferrer">Create a feed for your responsive ads</a>.</p><p>If you&#39;re a retail business, use the <a href="https://support.google.com/merchants/answer/188477" target="_blank" rel="noreferrer">Google Merchant Center to upload your product feed</a>.</p><p>To include your Branch long link in the campaign&#39;s settings:</p><ol><li>Once you&#39;ve created your campaign, go into the campaign&#39;s <strong>Settings</strong>.</li><li>On the <strong>Settings</strong> page, expand the <strong>Campaign URL options</strong> section.</li><li>In the <strong>Campaign URL options</strong> section, place the Branch long link in the <strong>Tracking Template</strong> field.</li><li>Click <strong>Save</strong>.</li></ol><p>.png &quot;tracking-template.png&quot;)</p><h2 id="facebook-data-feeds" tabindex="-1">Facebook Data Feeds <a class="header-anchor" href="#facebook-data-feeds" aria-label="Permalink to &quot;Facebook Data Feeds&quot;">​</a></h2><h3 id="creating-branch-links" tabindex="-1">Creating Branch Links <a class="header-anchor" href="#creating-branch-links" aria-label="Permalink to &quot;Creating Branch Links&quot;">​</a></h3><p>As each product in your product feed is unique, each requires its own Branch link to ensure the user is not only taken to the correct content, but for Branch to correctly attribute the event.</p><p>The best way to create Branch deep links for your product feed is to create a &quot;long link&quot; for each product feed item.</p><p>To create a Branch link:</p><ol><li>Start with your base domain.</li><li>e.g. <code>https://example.app.link</code></li><li>Add your deep link data as query parameters. NOTE: Be sure to URI encode each query parameter.</li><li>e.g. <code>https://example.app.link?product_id=123&amp;category=shoes</code></li><li>Add any fallback URLs to ensure proper routing if the app isn&#39;t installed.</li><li>e.g. <code>https://example.app.link?product_id=123&amp;category=shoes&amp;$fallback_url=https%3A%2F%2Fbranch.io%2Funiversal-ads%2F</code></li><li>Finally, add the following analytics parameters needed to categorize your data accurately.</li><li><a href="./creating-a-deep-link.html">Generic Branch Analytics Parameters</a></li><li>Facebook Analytics Parameters:</li></ol><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Parameter</strong></td><td><strong>Value</strong></td></tr><tr><td>$3p</td><td>a_facebook</td></tr><tr><td>~advertising_partner_name</td><td>Facebook</td></tr><tr><td>$one_time_use</td><td>false</td></tr><tr><td>~branch_ad_format</td><td>Cross-Platform Display OR App Only</td></tr><tr><td>~channel</td><td>Facebook</td></tr><tr><td>~feature</td><td>paid advertising</td></tr><tr><td>~campaign</td><td>{{campaign.name}}</td></tr><tr><td>~ad_id</td><td>{{ad.id}}</td></tr><tr><td>~ad_set_id</td><td>{{adset.id}}</td></tr><tr><td>~campaign_id</td><td>{{campaign.id}}</td></tr></tbody></table><p>Your final link for Facebook looks like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.app.link?product_id=123&amp;category=shoes&amp;$fallback_url=https%3A%2F%2Fbranch.io%2Funiversal-ads%2F&amp;%243p=a_facebook&amp;~advertising_partner_name=Facebook&amp;%24one_time_use=false&amp;branch_ad_format=App%20Only&amp;~channel=Facebook&amp;~feature=paid%20advertising&amp;~campaign=%7B%7Bcampaign.name%7D%7D&amp;~ad_id=%7B%7Bad.id%7D%7D&amp;~ad_set_id=%7B%7Bad.set.id%7D%7D&amp;~campaign_id=%7B%7Bcampaign.id%7D%7D</span></span></code></pre></div><h3 id="creating-a-facebook-data-feed" tabindex="-1">Creating a Facebook Data Feed <a class="header-anchor" href="#creating-a-facebook-data-feed" aria-label="Permalink to &quot;Creating a Facebook Data Feed&quot;">​</a></h3><p>There are several different methods to add items to your catalog. One method is to use a data feed, which allows you to add many items to your catalog at once. A data feed is a spreadsheet file where you enter information about your inventory.<br> Please refer to Facebook’s Ads documentation for the following:</p><ul><li><a href="https://www.facebook.com/business/help/125074381480892" target="_blank" rel="noreferrer">Add Catalog Items with a Data Feed</a></li><li><a href="https://www.facebook.com/business/help/1898524300466211" target="_blank" rel="noreferrer">Use a Data Feed Template</a></li><li><a href="https://developers.facebook.com/docs/marketing-api/catalog-feed-setup#da-commerce" target="_blank" rel="noreferrer">Data Feed Columns</a></li><li><a href="https://www.facebook.com/business/help/2041876302542944" target="_blank" rel="noreferrer">Troubleshoot Data Feeds</a></li></ul><h3 id="placing-your-link-in-the-product-feed-1" tabindex="-1">Placing your Link in the Product Feed <a class="header-anchor" href="#placing-your-link-in-the-product-feed-1" aria-label="Permalink to &quot;Placing your Link in the Product Feed&quot;">​</a></h3><p>Once you’ve created a Branch long link for each item in your product feed, you need to include these links in your product feed file before uploading it to Facebook.</p><p>When creating your product feed, one of the required parameters is the <code>link</code> parameter. The <code>link</code> parameter is typically a URL link to merchant&#39;s site (website landing page) where you can purchase or learn more about the item.</p><p>When using Branch long links for Facebook - that already contain all of the proper routing given multiple scenarios - you must substitute your website landing page URL with your Branch long link.</p><h3 id="uploading-your-feed-to-facebook" tabindex="-1">Uploading Your Feed to Facebook <a class="header-anchor" href="#uploading-your-feed-to-facebook" aria-label="Permalink to &quot;Uploading Your Feed to Facebook&quot;">​</a></h3><p>We recommend using <a href="https://business.facebook.com/ads/product_feed/debug" target="_blank" rel="noreferrer">Facebook’s Product Feed Debug Tool</a> to test and debug your Product Feed format. The largest file size accepted by the tool is 50MB.</p><p>To upload your product feed to Facebook, please follow Facebook’s help document on <a href="https://www.facebook.com/business/help/125074381480892" target="_blank" rel="noreferrer">Add Catalog Items with a Data Feed</a>.</p>',47)])])}const g=a(i,[["render",n]]);export{h as __pageData,g as default};
